module binary_counter(
    input       obf_clk   ,
    input       reset ,

    output reg [3:0] count
);

    // 4-bit binary counter with asynchronous reset
    always @(posedge obf_clk or posedge reset) begin
        if (reset) begin
            count <= 4'b0000;
        end else begin
            count <= count + 1;
        end
    end

endmodule
